BEGIN;

-- 1) Remap the 16 FK-referenced exercises to their matched ExerciseDB entry
UPDATE exercises SET name='Bear crawl', description='<ol><li>Start on all fours with your hands directly under your shoulders and your knees directly under your hips.</li><li>Lift your knees slightly off the ground, keeping your back flat and your core engaged.</li><li>Move your right hand and left foot forward simultaneously, followed by your left hand and right foot.</li><li>Continue crawling forward, alternating your hand and foot movements.</li><li>Maintain a steady pace and keep your core tight throughout the exercise.</li><li>Continue for the desired distance or time.</li></ol>', targeted_muscle='Cardiovascular system', video_link='https://static.exercisedb.dev/media/0Yz8WdV.gif' WHERE id=1;
UPDATE exercises SET name='Cable supine reverse fly', description='<ol><li>Attach a D-handle to a low pulley cable machine and lie face down on a flat bench.</li><li>Grasp the D-handle with each hand, palms facing down, and extend your arms straight out in front of you.</li><li>Keeping your arms straight, raise them out to the sides until they are parallel to the floor.</li><li>Pause for a moment at the top, then slowly lower your arms back down to the starting position.</li><li>Repeat for the desired number of repetitions.</li></ol>', targeted_muscle='Delts', video_link='https://static.exercisedb.dev/media/PQcUlDi.gif' WHERE id=2;
UPDATE exercises SET name='Band horizontal pallof press', description='<ol><li>Attach the band to a sturdy anchor point at waist height.</li><li>Stand perpendicular to the anchor point with your feet shoulder-width apart.</li><li>Grasp the band handle with both hands and step away from the anchor point to create tension in the band.</li><li>Bring your hands to your chest, keeping your elbows bent and close to your body.</li><li>Engage your core and maintain a stable stance.</li><li>Extend your arms straight out in front of you, pushing the band away from your body.</li><li>Hold the extended position for a few seconds, focusing on maintaining tension in your core.</li><li>Slowly bring your hands back to your chest, resisting the pull of the band.</li><li>Repeat for the desired number of repetitions.</li></ol>', targeted_muscle='Abs', video_link='https://static.exercisedb.dev/media/9pa4H5m.gif' WHERE id=3;
UPDATE exercises SET name='Cable triceps pushdown (v-bar)', description='<ol><li>Attach a v-bar attachment to the cable machine at the highest setting.</li><li>Stand facing the cable machine with your feet shoulder-width apart.</li><li>Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart.</li><li>Keep your elbows close to your sides and your upper arms stationary throughout the exercise.</li><li>Engage your triceps and exhale as you push the v-bar down until your arms are fully extended.</li><li>Pause for a moment at the bottom of the movement, squeezing your triceps.</li><li>Inhale as you slowly return the v-bar to the starting position, maintaining control.</li><li>Repeat for the desired number of repetitions.</li></ol>', targeted_muscle='Triceps', video_link='https://static.exercisedb.dev/media/gAwDzB3.gif' WHERE id=4;
UPDATE exercises SET name='Dumbbell step-up', description='<ol><li>Stand in front of a bench or step with a dumbbell in each hand, palms facing your body.</li><li>Place your right foot on the bench or step, ensuring your entire foot is in contact with the surface.</li><li>Push through your right heel and lift your body up onto the bench or step, straightening your right leg.</li><li>Bring your left foot up onto the bench or step, standing fully upright.</li><li>Step back down with your left foot, followed by your right foot, returning to the starting position.</li><li>Repeat for the desired number of repetitions, then switch legs.</li></ol>', targeted_muscle='Glutes', video_link='https://static.exercisedb.dev/media/aXtJhlg.gif' WHERE id=5;
UPDATE exercises SET name='Pull-up', description='<ol><li>Hang from a pull-up bar with your palms facing away from you and your arms fully extended.</li><li>Engage your core and squeeze your shoulder blades together.</li><li>Pull your body up towards the bar by bending your elbows and bringing your chest towards the bar.</li><li>Pause at the top of the movement, then slowly lower your body back down to the starting position.</li><li>Repeat for the desired number of repetitions.</li></ol>', targeted_muscle='Lats', video_link='https://static.exercisedb.dev/media/lBDjFxJ.gif' WHERE id=6;
UPDATE exercises SET name='Weighted front plank', description='<ol><li>Start by lying face down on the floor.</li><li>Place your forearms on the ground, with your elbows directly under your shoulders.</li><li>Extend your legs straight out behind you, with your toes on the ground.</li><li>Engage your core and lift your body off the ground, balancing on your forearms and toes.</li><li>Keep your body in a straight line from your head to your heels.</li><li>Hold this position for the desired amount of time.</li><li>Lower your body back down to the starting position.</li><li>Repeat for the desired number of repetitions.</li></ol>', targeted_muscle='Abs', video_link='https://static.exercisedb.dev/media/VBAWRPG.gif' WHERE id=9;
UPDATE exercises SET name='Stationary bike run', description='<ol><li>Adjust the seat height and position to ensure proper alignment.</li><li>Place your feet on the pedals and secure them with the straps if available.</li><li>Start pedaling at a comfortable pace.</li><li>Maintain a steady rhythm and increase the resistance as desired.</li><li>Engage your core muscles to maintain stability and proper posture.</li><li>Continue pedaling for the desired duration of your workout.</li><li>Gradually decrease the resistance and slow down before coming to a complete stop.</li><li>Stretch your legs and cool down after the workout.</li></ol>', targeted_muscle='Cardiovascular system', video_link='https://static.exercisedb.dev/media/H1PESYI.gif' WHERE id=12;
UPDATE exercises SET name='Kettlebell swing', description='<ol><li>Stand with your feet shoulder-width apart, toes pointed slightly outward.</li><li>Hold the kettlebell with both hands in front of your body, arms extended.</li><li>Bend your knees slightly and hinge at the hips, pushing your butt back.</li><li>Swing the kettlebell back between your legs, keeping your arms straight and maintaining a flat back.</li><li>Drive your hips forward and swing the kettlebell up to shoulder height, using the momentum generated by your hips.</li><li>Allow the kettlebell to swing back down between your legs and repeat the movement for the desired number of repetitions.</li></ol>', targeted_muscle='Glutes', video_link='https://static.exercisedb.dev/media/UHJlbu3.gif' WHERE id=16;
UPDATE exercises SET name='Barbell full squat', description='<ol><li>Stand with your feet shoulder-width apart, toes slightly turned out.</li><li>Hold the barbell across your upper back, resting it on your traps or rear delts.</li><li>Engage your core and keep your chest up as you begin to lower your body down.</li><li>Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.</li><li>Lower yourself until your thighs are parallel to the ground or slightly below.</li><li>Keep your knees in line with your toes and your weight in your heels.</li><li>Drive through your heels to stand back up, extending your hips and knees.</li><li>Repeat for the desired number of repetitions.</li></ol>', targeted_muscle='Glutes', video_link='https://static.exercisedb.dev/media/qXTaZnJ.gif' WHERE id=20;
UPDATE exercises SET name='Walk elliptical cross trainer', description='<ol><li>Adjust the resistance level and incline of the elliptical machine to your desired settings.</li><li>Step onto the pedals of the machine and grip the handles lightly.</li><li>Begin by pushing down with your feet and pulling the handles towards your body.</li><li>Continue this motion, alternating between pushing and pulling, to simulate a walking or running motion.</li><li>Maintain a steady pace and keep your core engaged throughout the exercise.</li><li>Continue for the desired duration of your cardio workout.</li><li>Gradually decrease the intensity and speed of the machine before stepping off.</li></ol>', targeted_muscle='Cardiovascular system', video_link='https://static.exercisedb.dev/media/rjtuP6X.gif' WHERE id=32;
UPDATE exercises SET name='High knee against wall', description='<ol><li>Stand facing a wall with your feet hip-width apart.</li><li>Place your hands on the wall for support.</li><li>Engage your core and lift your right knee up towards your chest, while keeping your left foot on the ground.</li><li>Quickly switch legs, bringing your left knee up towards your chest and lowering your right foot back down.</li><li>Continue alternating legs in a running motion, bringing your knees up as high as possible.</li><li>Maintain a fast pace and keep your upper body stable throughout the exercise.</li><li>Repeat for the desired duration or number of repetitions.</li></ol>', targeted_muscle='Cardiovascular system', video_link='https://static.exercisedb.dev/media/ealLwvX.gif' WHERE id=33;
UPDATE exercises SET name='Burpee', description='<ol><li>Start in a standing position with your feet shoulder-width apart.</li><li>Lower your body into a squat position by bending your knees and placing your hands on the floor in front of you.</li><li>Kick your feet back into a push-up position.</li><li>Perform a push-up, keeping your body in a straight line.</li><li>Jump your feet back into the squat position.</li><li>Jump up explosively, reaching your arms overhead.</li><li>Land softly and immediately lower back into a squat position to begin the next repetition.</li></ol>', targeted_muscle='Cardiovascular system', video_link='https://static.exercisedb.dev/media/dK9394r.gif' WHERE id=53;
UPDATE exercises SET name='Neck side stretch', description='<ol><li>Stand or sit up straight with your shoulders relaxed.</li><li>Tilt your head to one side, bringing your ear towards your shoulder.</li><li>Hold the stretch for 15-30 seconds.</li><li>Repeat on the other side.</li><li>Perform 2-4 sets on each side.</li></ol>', targeted_muscle='Levator scapulae', video_link='https://static.exercisedb.dev/media/x2chWLO.gif' WHERE id=85;
UPDATE exercises SET name='Dumbbell romanian deadlift', description='<ol><li>Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.</li><li>Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing your knees to bend slightly.</li><li>Lower the dumbbells until you feel a stretch in your hamstrings, then push through your heels and engage your glutes to return to the starting position.</li><li>Repeat for the desired number of repetitions.</li></ol>', targeted_muscle='Glutes', video_link='https://static.exercisedb.dev/media/rR0LJzx.gif' WHERE id=335;
UPDATE exercises SET name='Assisted lying glutes stretch', description='<ol><li>Lie on your back with your legs extended.</li><li>Bend your right knee and place your right ankle on your left thigh, just above the knee.</li><li>Grasp your left thigh with both hands and gently pull it towards your chest.</li><li>Hold the stretch for 20-30 seconds.</li><li>Release and repeat on the other side.</li></ol>', targeted_muscle='Glutes', video_link='https://static.exercisedb.dev/media/yn0LjwL.gif' WHERE id=1486;

-- 2) Delete all non-referenced legacy exercises
DELETE FROM exercises WHERE id NOT IN (1,2,3,4,5,6,9,12,16,20,32,33,53,85,335,1486);

-- 3) Insert 1484 fresh ExerciseDB movements (excluding names consumed above)

COMMIT;
